import{_ as l,o as e,c as a,a2 as o}from"./chunks/framework.iesXg5kS.js";const b=JSON.parse('{"title":"高质量 vibe Coding的准则","description":"","frontmatter":{},"headers":[],"relativePath":"vibe coding/高质量vibe Coding的准则.md","filePath":"vibe coding/高质量vibe Coding的准则.md","lastUpdated":1781229017000}'),t={name:"vibe coding/高质量vibe Coding的准则.md"};function d(n,i,r,p,_,c){return e(),a("div",null,[...i[0]||(i[0]=[o('<h1 id="高质量-vibe-coding的准则" tabindex="-1">高质量 vibe Coding的准则 <a class="header-anchor" href="#高质量-vibe-coding的准则" aria-label="Permalink to &quot;高质量 vibe Coding的准则&quot;">​</a></h1><ol><li>不是说你直接把任务扔给他就行了，就不用管了</li></ol><h1 id="项目开始前-如何保证生成的内容高质量" tabindex="-1">项目开始前（如何保证生成的内容高质量） <a class="header-anchor" href="#项目开始前-如何保证生成的内容高质量" aria-label="Permalink to &quot;项目开始前（如何保证生成的内容高质量）&quot;">​</a></h1><ol><li><p>（定好标准）先别去写代码，先导需求，让他输出一份prd文档，你定个验收标准，（你要输出的这个prd文档，每个需求你要做到什么时候才算完成），比如做登录时候，登录时候的校验怎么判断，登录成功怎么处理，登录失败错误提示是什么，做到这种程度就ok。要不然他最终生成的结果是非常发散的，不可控的。</p></li><li><p>明确项目的边界，和非功能需求</p><ol><li>上线后用户访问量大不大</li><li>有没有用户的数据，隐私是如何处理</li><li>有没有支付，im等功能</li><li>性能和成本有没有上限</li></ol></li><li><p>项目的技术选型</p><ol><li>技术选型的时候，不是最新的就是最好的，而是选择目前最主流的技术</li><li>主流的技术有几大好处，文档多，示例多，ai不容易瞎说，生成的产品质量更稳定，效果更好</li></ol></li><li><p>项目中新建项目级别的md文档</p><ol><li>PRD.md (描述需求变更的)</li><li>ARCH.md （描述架构的）</li><li>PROJECT.md （描述项目目前所处的阶段的）（比如现在项目做了哪些，现在有哪些问题，接来下要做什么）</li></ol></li></ol><p>这个就是Ai的全局上下文，之后项目有大的改动，这三个文档也要同步修改（这个是比较重要的，否则ai会去按照旧的世界观去写代码）</p><p>agent.md 里面放一些，规范，比如必须用typescript，组件的命名规则，文件的大小上限等 另外我们还可以建一个reference这样的文件夹，放一些我们认可的表单呀，弹窗的组件的实现</p><h1 id="项目进行中-如何保证生成的内容高质量呢" tabindex="-1">项目进行中（如何保证生成的内容高质量呢） <a class="header-anchor" href="#项目进行中-如何保证生成的内容高质量呢" aria-label="Permalink to &quot;项目进行中（如何保证生成的内容高质量呢）&quot;">​</a></h1><ol><li>坚守一个小步迭代的功能的法则。不要一下给ai一个超级长，超级复杂的任务，要主动去拆分。</li><li>人类必须要介入（文件不要太大，要保证文件的可读性）</li><li>限制ai权限，不要做越界的事情，（说明白只修改我指定的文件或模块，不用无关的文件，不要顺手重构）</li><li>科学的应对报错 第一次应对报错的时候，可以把错误，丢给ai 如果连续几次，他仍然一致报错处理，那你就把这个错误停掉，开启新的任务</li></ol>',8)])])}const m=l(t,[["render",d]]);export{b as __pageData,m as default};
